{
  "name": "Physics Phrontier",
  "description": "An interactive physics education platform for high school students and competitive exam aspirants, featuring simulations, worksheets, and specialized Indian Astronomy modules.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  ADMIN = 'ADMIN',
  STUDENT = 'STUDENT'
}

export enum ResourceType {
  SIMULATION = 'Simulation',
  WORKSHEET = 'Worksheet',
  CHEATSHEET = 'Cheatsheet'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
}

export interface PhysicsResource {
  id: string;
  title: string;
  category: string;
  subCategory: string;
  type: ResourceType;
  author: string;
  description: string;
  userGuide: string;
  learningOutcomes: string[];
  contentUrl: string; // URL for simulation (iframe) or PDF
  thumbnailUrl?: string;
  createdAt: string;
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  subCategories: string[];
}

import { GoogleGenAI, Type } from "@google/genai";

export const generateLearningOutcomes = async (title: string, category: string, description: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `As a physics expert, generate 3 clear learning outcomes for a resource titled "${title}" in the category "${category}". Description: ${description}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "An array of 3 learning outcomes."
      }
    }
  });

  try {
    return JSON.parse(response.text.trim());
  } catch (e) {
    return ["Understand the core concepts of " + title, "Apply theory to practical problems", "Analyze results effectively"];
  }
};

import React, { useState, useMemo } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useNavigate } from 'react-router-dom';
import { User, UserRole, PhysicsResource } from './types';
import { CATEGORIES, MOCK_RESOURCES } from './constants';
import Dashboard from './components/Dashboard';
import UploadForm from './components/UploadForm';
import SimulationPlayer from './components/SimulationPlayer';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [resources, setResources] = useState<PhysicsResource[]>(MOCK_RESOURCES);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string | null>(null);

  // Simple Auth simulation
  const login = (role: UserRole) => {
    setUser({ id: '1', name: role === UserRole.ADMIN ? 'Admin User' : 'Student Explorer', role });
  };

  const logout = () => setUser(null);

  const filteredResources = useMemo(() => {
    return resources.filter(res => {
      const matchesSearch = res.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            res.subCategory.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory ? res.category === activeCategory : true;
      return matchesSearch && matchesCategory;
    });
  }, [resources, searchQuery, activeCategory]);

  const handleAddResource = (newRes: PhysicsResource) => {
    setResources(prev => [newRes, ...prev]);
  };

  const handleDeleteResource = (id: string) => {
    setResources(prev => prev.filter(r => r.id !== id));
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-50 to-cyan-50 p-4">
        <div className="bg-white p-8 rounded-3xl shadow-xl w-full max-w-md text-center">
          <h1 className="text-4xl font-extrabold text-blue-600 mb-2">Physics Phrontier</h1>
          <p className="text-gray-500 mb-8 font-medium">Empowering JEE/NEET aspirants with interactive physics</p>
          <div className="space-y-4">
            <button 
              onClick={() => login(UserRole.STUDENT)}
              className="w-full py-4 bg-white border-2 border-blue-500 text-blue-600 rounded-xl font-bold hover:bg-blue-50 transition-colors"
            >
              Continue as Student
            </button>
            <button 
              onClick={() => login(UserRole.ADMIN)}
              className="w-full py-4 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 transition-shadow shadow-lg"
            >
              Admin Portal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-50 text-slate-800">
        <Sidebar 
          categories={CATEGORIES} 
          activeCategory={activeCategory} 
          onCategorySelect={setActiveCategory}
          onLogout={logout}
          userName={user.name}
          userRole={user.role}
        />

        <main className="flex-1 overflow-y-auto">
          {/* Header */}
          <header className="sticky top-0 z-10 bg-white/80 backdrop-blur-md border-b border-slate-200 px-6 py-4 flex items-center justify-between">
            <div className="relative w-full max-w-xl">
              <input 
                type="text"
                placeholder="Search topics, simulations, worksheets..."
                className="w-full pl-10 pr-4 py-2.5 bg-slate-100 border-none rounded-2xl focus:ring-2 focus:ring-blue-400 focus:bg-white transition-all outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
              <span className="absolute left-3 top-3 text-slate-400">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
              </span>
            </div>
            <div className="flex items-center gap-4 ml-4">
              {user.role === UserRole.ADMIN && (
                <Link 
                  to="/upload"
                  className="bg-blue-600 text-white px-5 py-2.5 rounded-xl font-semibold text-sm shadow-md hover:bg-blue-700 transition-all flex items-center gap-2"
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                  New Resource
                </Link>
              )}
            </div>
          </header>

          <div className="p-6">
            <Routes>
              <Route path="/" element={<Dashboard resources={filteredResources} isAdmin={user.role === UserRole.ADMIN} onDelete={handleDeleteResource} />} />
              <Route path="/upload" element={user.role === UserRole.ADMIN ? <UploadForm onAdd={handleAddResource} /> : <Navigate to="/" />} />
              <Route path="/play/:id" element={<SimulationPlayer resources={resources} />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { Link } from 'react-router-dom';
import { Category, UserRole } from '../types';

interface SidebarProps {
  categories: Category[];
  activeCategory: string | null;
  onCategorySelect: (id: string | null) => void;
  onLogout: () => void;
  userName: string;
  userRole: UserRole;
}

const Sidebar: React.FC<SidebarProps> = ({ categories, activeCategory, onCategorySelect, onLogout, userName, userRole }) => {
  return (
    <aside className="w-72 bg-white border-r border-slate-200 flex flex-col h-full overflow-hidden">
      <div className="p-6 border-b border-slate-100">
        <Link to="/" onClick={() => onCategorySelect(null)} className="flex items-center gap-3 group">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg group-hover:scale-110 transition-transform">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.691.346a6 6 0 01-3.86.517l-2.388-.477a2 2 0 00-1.022.547l-1.168 1.168a2 2 0 001.414 3.414h15.428a2 2 0 001.414-3.414l-1.168-1.168z"></path></svg>
          </div>
          <span className="text-xl font-bold bg-gradient-to-r from-blue-700 to-cyan-600 bg-clip-text text-transparent">Phys Phrontier</span>
        </Link>
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-6 scrollbar-hide">
        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2 mb-4">Core Library</h3>
        <nav className="space-y-1">
          <button 
            onClick={() => onCategorySelect(null)}
            className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-colors ${activeCategory === null ? 'bg-blue-50 text-blue-600 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}
          >
            <span>📚</span> All Resources
          </button>

          {categories.map((cat) => (
            <button
              key={cat.id}
              onClick={() => onCategorySelect(cat.name)}
              className={`w-full text-left px-4 py-3 rounded-xl flex items-center gap-3 transition-colors ${activeCategory === cat.name ? 'bg-blue-50 text-blue-600 font-bold' : 'text-slate-600 hover:bg-slate-50'}`}
            >
              <span className="text-xl">{cat.icon}</span>
              <span className="truncate">{cat.name}</span>
            </button>
          ))}
        </nav>
      </div>

      <div className="p-4 bg-slate-50 border-t border-slate-200 space-y-4">
        <div className="flex items-center gap-3 px-2">
          <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold">
            {userName.charAt(0)}
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-sm font-semibold text-slate-900 truncate">{userName}</p>
            <p className="text-xs text-slate-500 capitalize">{userRole.toLowerCase()}</p>
          </div>
        </div>
        <button 
          onClick={onLogout}
          className="w-full flex items-center justify-center gap-2 py-2.5 text-red-500 hover:bg-red-50 rounded-xl transition-colors font-semibold text-sm"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1"></path></svg>
          Logout
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

import React from 'react';
import { PhysicsResource } from '../types';
import ResourceCard from './ResourceCard';

interface DashboardProps {
  resources: PhysicsResource[];
  isAdmin: boolean;
  onDelete: (id: string) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ resources, isAdmin, onDelete }) => {
  return (
    <div>
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-extrabold text-slate-900">Explore Resources</h2>
          <p className="text-slate-500 mt-1">Found {resources.length} interactive learning materials</p>
        </div>
      </div>

      {resources.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-24 text-center">
          <div className="w-24 h-24 bg-slate-100 rounded-full flex items-center justify-center mb-6">
            <svg className="w-10 h-10 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
          </div>
          <h3 className="text-xl font-bold text-slate-800">No results found</h3>
          <p className="text-slate-500 max-w-xs mt-2">Try adjusting your search or category filters to find what you're looking for.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {resources.map((res) => (
            <ResourceCard key={res.id} resource={res} isAdmin={isAdmin} onDelete={onDelete} />
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React from 'react';
import { Link } from 'react-router-dom';
import { PhysicsResource, ResourceType } from '../types';

interface ResourceCardProps {
  resource: PhysicsResource;
  isAdmin: boolean;
  onDelete: (id: string) => void;
}

const ResourceCard: React.FC<ResourceCardProps> = ({ resource, isAdmin, onDelete }) => {
  const getBadgeColor = (type: ResourceType) => {
    switch (type) {
      case ResourceType.SIMULATION: return 'bg-blue-100 text-blue-700';
      case ResourceType.WORKSHEET: return 'bg-emerald-100 text-emerald-700';
      case ResourceType.CHEATSHEET: return 'bg-amber-100 text-amber-700';
      default: return 'bg-slate-100 text-slate-700';
    }
  };

  return (
    <div className="group relative bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300">
      <div className="h-48 relative overflow-hidden bg-gradient-to-br from-blue-500 to-cyan-500 flex items-center justify-center text-white">
        {resource.thumbnailUrl ? (
          <img src={resource.thumbnailUrl} alt={resource.title} className="w-full h-full object-cover" />
        ) : (
          <div className="p-8 text-center flex flex-col items-center">
             <div className="text-5xl mb-3 transform group-hover:scale-125 transition-transform duration-500 drop-shadow-lg">
               {resource.category === 'Astronomy' ? '🪐' : '🔭'}
             </div>
             <p className="font-black text-lg leading-tight opacity-90 uppercase tracking-tighter">{resource.title}</p>
          </div>
        )}
        <div className="absolute top-4 left-4">
          <span className={`px-3 py-1 rounded-full text-xs font-bold shadow-sm ${getBadgeColor(resource.type)}`}>
            {resource.type}
          </span>
        </div>
        {isAdmin && (
          <button 
            onClick={(e) => { e.preventDefault(); onDelete(resource.id); }}
            className="absolute top-4 right-4 bg-white/20 backdrop-blur-md p-2 rounded-full text-white hover:bg-red-500 transition-colors"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
          </button>
        )}
      </div>

      <div className="p-5">
        <div className="flex items-center gap-2 mb-2">
          <span className="text-xs font-bold text-blue-600 uppercase tracking-wider">{resource.category}</span>
          <span className="text-slate-300">•</span>
          <span className="text-xs text-slate-500 truncate">{resource.subCategory}</span>
        </div>
        <h3 className="font-bold text-slate-900 text-lg mb-2 line-clamp-1">{resource.title}</h3>
        <p className="text-slate-500 text-sm line-clamp-2 mb-4 leading-relaxed">{resource.description}</p>

        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="w-6 h-6 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-bold text-slate-600">
              {resource.author.charAt(0)}
            </div>
            <span className="text-xs text-slate-500 font-medium">{resource.author}</span>
          </div>

          <Link 
            to={`/play/${resource.id}`}
            className="text-blue-600 text-sm font-bold flex items-center gap-1 hover:underline group-hover:gap-2 transition-all"
          >
            {resource.type === ResourceType.SIMULATION ? 'Play Now' : 'View File'}
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ResourceCard;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { PhysicsResource, ResourceType } from '../types';
import { CATEGORIES } from '../constants';
import { generateLearningOutcomes } from '../services/geminiService';

interface UploadFormProps {
  onAdd: (resource: PhysicsResource) => void;
}

const UploadForm: React.FC<UploadFormProps> = ({ onAdd }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    category: CATEGORIES[0].name,
    subCategory: '',
    type: ResourceType.SIMULATION,
    author: '',
    description: '',
    userGuide: '',
    contentUrl: '',
    learningOutcomes: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const newResource: PhysicsResource = {
      id: Date.now().toString(),
      title: formData.title,
      category: formData.category,
      subCategory: formData.subCategory,
      type: formData.type,
      author: formData.author,
      description: formData.description,
      userGuide: formData.userGuide,
      contentUrl: formData.contentUrl,
      learningOutcomes: formData.learningOutcomes.split('\n').filter(o => o.trim() !== ''),
      createdAt: new Date().toISOString()
    };
    onAdd(newResource);
    navigate('/');
  };

  const handleSuggestOutcomes = async () => {
    if (!formData.title || !formData.description) {
      alert("Please provide a title and description first.");
      return;
    }
    setLoading(true);
    const outcomes = await generateLearningOutcomes(formData.title, formData.category, formData.description);
    setFormData(prev => ({ ...prev, learningOutcomes: outcomes.join('\n') }));
    setLoading(false);
  };

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center gap-4 mb-8">
        <button onClick={() => navigate(-1)} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7 7-7m8 14l-7-7 7-7"></path></svg>
        </button>
        <h1 className="text-3xl font-extrabold text-slate-900">Add New Resource</h1>
      </div>

      <form onSubmit={handleSubmit} className="space-y-8 bg-white p-8 rounded-3xl border border-slate-200 shadow-xl">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Resource Title</label>
            <input 
              required
              type="text"
              className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
              placeholder="e.g. Newton's Second Law Simulation"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Author / Creator</label>
            <input 
              required
              type="text"
              className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
              placeholder="Your name or organization"
              value={formData.author}
              onChange={(e) => setFormData({ ...formData, author: e.target.value })}
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Category</label>
            <select 
              className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
              value={formData.category}
              onChange={(e) => setFormData({ ...formData, category: e.target.value })}
            >
              {CATEGORIES.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Sub-category</label>
            <input 
              required
              type="text"
              className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
              placeholder="e.g. Dynamics"
              value={formData.subCategory}
              onChange={(e) => setFormData({ ...formData, subCategory: e.target.value })}
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Resource Type</label>
            <div className="flex gap-4">
              {Object.values(ResourceType).map(type => (
                <button
                  key={type}
                  type="button"
                  onClick={() => setFormData({ ...formData, type })}
                  className={`flex-1 py-3 rounded-xl border-2 font-bold text-sm transition-all ${formData.type === type ? 'border-blue-500 bg-blue-50 text-blue-600' : 'border-slate-100 text-slate-400 hover:border-slate-200'}`}
                >
                  {type}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-bold text-slate-700">Content URL (Simulation or File Link)</label>
            <input 
              required
              type="url"
              className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
              placeholder="https://..."
              value={formData.contentUrl}
              onChange={(e) => setFormData({ ...formData, contentUrl: e.target.value })}
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700">Short Description</label>
          <textarea 
            required
            rows={2}
            className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
            placeholder="A brief overview of what this resource covers..."
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          />
        </div>

        <div className="space-y-2">
          <label className="text-sm font-bold text-slate-700">User Guide / Instructions</label>
          <textarea 
            required
            rows={2}
            className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
            placeholder="Step-by-step instructions for the student..."
            value={formData.userGuide}
            onChange={(e) => setFormData({ ...formData, userGuide: e.target.value })}
          />
        </div>

        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <label className="text-sm font-bold text-slate-700">Learning Outcomes (one per line)</label>
            <button 
              type="button"
              onClick={handleSuggestOutcomes}
              disabled={loading}
              className="text-blue-600 text-xs font-black uppercase hover:underline flex items-center gap-1 disabled:opacity-50"
            >
              {loading ? 'AI Thinking...' : '✨ Suggest with Gemini AI'}
            </button>
          </div>
          <textarea 
            required
            rows={4}
            className="w-full px-4 py-3 rounded-xl bg-slate-50 border border-slate-200 focus:ring-2 focus:ring-blue-400 outline-none"
            placeholder="1. Understand friction forces&#10;2. Calculate coefficients of static friction..."
            value={formData.learningOutcomes}
            onChange={(e) => setFormData({ ...formData, learningOutcomes: e.target.value })}
          />
        </div>

        <div className="pt-4 border-t border-slate-100 flex justify-end gap-4">
          <button 
            type="button"
            onClick={() => navigate(-1)}
