import React, { useState, useMemo, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { User, UserRole, PhysicsResource } from './types';
import { CATEGORIES, MOCK_RESOURCES } from './constants';
import Dashboard from './components/Dashboard';
import UploadForm from './components/UploadForm';
import SimulationPlayer from './components/SimulationPlayer';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [resources, setResources] = useState<PhysicsResource[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string | null>(null);
  const [isSidebarOpen, setSidebarOpen] = useState(false);
  const [editingResource, setEditingResource] = useState<PhysicsResource | null>(null);

  // Initialize data from LocalStorage or Mock
  useEffect(() => {
    const saved = localStorage.getItem('phrontier_resources');
    if (saved) {
      try {
        setResources(JSON.parse(saved));
      } catch (e) {
        setResources(MOCK_RESOURCES);
      }
    } else {
      setResources(MOCK_RESOURCES);
    }
  }, []);

  // Save to LocalStorage whenever resources change
  useEffect(() => {
    if (resources.length > 0) {
      localStorage.setItem('phrontier_resources', JSON.stringify(resources));
    }
  }, [resources]);

  const login = (role: UserRole) => {
    setUser({ id: '1', name: role === UserRole.ADMIN ? 'Admin User' : 'Student Explorer', role });
  };

  const logout = () => setUser(null);

  // Advanced Search through all metadata
  const filteredResources = useMemo(() => {
    return resources.filter(res => {
      const searchStr = `${res.title} ${res.description} ${res.author} ${res.category} ${res.subCategory}`.toLowerCase();
      const matchesSearch = searchStr.includes(searchQuery.toLowerCase());
      const matchesCategory = activeCategory ? res.category === activeCategory : true;
      return matchesSearch && matchesCategory;
    });
  }, [resources, searchQuery, activeCategory]);

  const handleAddResource = (newRes: PhysicsResource) => {
    setResources(prev => [newRes, ...prev]);
  };

  const handleUpdateResource = (updatedRes: PhysicsResource) => {
    setResources(prev => prev.map(r => r.id === updatedRes.id ? updatedRes : r));
    setEditingResource(null);
  };

  const handleDeleteResource = (id: string) => {
    if(confirm("Are you sure you want to delete this resource?")) {
      setResources(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleEditClick = (res: PhysicsResource) => {
    setEditingResource(res);
  };

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#020617] p-4 relative overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_50%,rgba(79,70,229,0.1),transparent_50%)]"></div>
        <div className="absolute top-0 left-0 w-full h-full bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-20 pointer-events-none"></div>

        <div className="bg-white/5 backdrop-blur-2xl p-8 sm:p-12 rounded-[3.5rem] shadow-2xl w-full max-w-md text-center border border-white/10 relative z-10 animate-in fade-in zoom-in-95 duration-1000">
          <div className="mb-10 inline-flex p-6 bg-gradient-to-br from-indigo-600 to-violet-600 rounded-[2rem] shadow-2xl shadow-indigo-500/40 transform -rotate-6">
             <svg className="w-12 h-12 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.691.346a6 6 0 01-3.86.517l-2.388-.477a2 2 0 00-1.022.547l-1.168 1.168a2 2 0 001.414 3.414h15.428a2 2 0 001.414-3.414l-1.168-1.168z"></path></svg>
          </div>
          <h1 className="text-5xl font-black text-white mb-3 tracking-tighter">Physics Phrontier</h1>
          <p className="text-indigo-300/60 mb-12 font-bold uppercase text-[10px] tracking-[0.3em]">Interactive Lab OS v2.1</p>

          <div className="space-y-4">
            <button 
              onClick={() => login(UserRole.STUDENT)}
              className="group w-full py-5 bg-white text-indigo-900 rounded-3xl font-black text-sm uppercase tracking-widest hover:bg-indigo-50 transition-all active:scale-95 shadow-xl flex items-center justify-center gap-3"
            >
              Start Exploring
              <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 7l5 5m0 0l-5 5m5-5H6"></path></svg>
            </button>
            <button 
              onClick={() => login(UserRole.ADMIN)}
              className="w-full py-5 bg-white/5 text-slate-300 border border-white/10 rounded-3xl font-black text-xs uppercase tracking-[0.2em] hover:bg-white/10 transition-all active:scale-95"
            >
              Admin Terminal
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-[#0F172A] text-slate-200 relative overflow-hidden">
        {isSidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/60 backdrop-blur-md z-40 lg:hidden"
            onClick={() => setSidebarOpen(false)}
          ></div>
        )}

        <Sidebar 
          categories={CATEGORIES} 
          activeCategory={activeCategory} 
          onCategorySelect={(cat) => {
            setActiveCategory(cat);
            setSidebarOpen(false);
          }}
          onLogout={logout}
          userName={user.name}
          userRole={user.role}
          isOpen={isSidebarOpen}
        />

        <main className="flex-1 overflow-y-auto w-full relative">
          <header className="sticky top-0 z-30 bg-[#0F172A]/80 backdrop-blur-2xl border-b border-white/5 px-6 sm:px-10 py-5 flex items-center justify-between">
            <div className="flex items-center gap-6 flex-1">
              <button 
                onClick={() => setSidebarOpen(true)}
                className="lg:hidden p-3 text-slate-400 hover:bg-white/5 rounded-2xl transition-colors"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"></path></svg>
              </button>
              <div className="relative w-full max-w-lg group">
                <input 
                  type="text"
                  placeholder="Search labs, authors, topics..."
                  className="w-full pl-14 pr-6 py-4 bg-[#1E293B] border border-white/5 rounded-[1.5rem] focus:ring-4 focus:ring-indigo-500/20 focus:bg-[#1E293B] focus:border-indigo-500/50 transition-all outline-none text-sm font-bold placeholder:text-slate-500"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <span className="absolute left-5 top-4.5 text-slate-500 group-focus-within:text-indigo-400 transition-colors">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
                </span>
              </div>
            </div>

            <div className="flex items-center gap-4 ml-6">
              <button 
                onClick={() => {setSearchQuery(''); setActiveCategory(null);}}
                className="p-4 bg-white/5 border border-white/10 text-slate-400 rounded-2xl hover:text-white transition-colors"
                title="Reset All Filters"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15"></path></svg>
              </button>

              {user.role === UserRole.ADMIN && (
                <Link 
                  to="/upload"
                  className="hidden md:flex bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-indigo-500/20 hover:bg-indigo-500 hover:-translate-y-1 transition-all items-center gap-3"
                  onClick={() => setEditingResource(null)}
                >
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4"></path></svg>
                  New Experiment
                </Link>
              )}
            </div>
          </header>

          <div className="p-6 sm:p-10 max-w-[1600px] mx-auto scrollbar-hide">
            <Routes>
              <Route path="/" element={
                <Dashboard 
                  resources={filteredResources} 
                  isAdmin={user.role === UserRole.ADMIN} 
                  onDelete={handleDeleteResource} 
                  onEdit={handleEditClick} 
                />
              } />
              <Route path="/upload" element={
                user.role === UserRole.ADMIN ? 
                <UploadForm onAdd={handleAddResource} onUpdate={handleUpdateResource} editData={editingResource} /> : 
                <Navigate to="/" />
              } />
              <Route path="/play/:id" element={<SimulationPlayer resources={resources} />} />
              <Route path="*" element={<Navigate to="/" />} />
            </Routes>
          </div>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { PhysicsResource, ResourceType } from '../types';

interface ResourceCardProps {
  resource: PhysicsResource;
  isAdmin: boolean;
  onDelete: (id: string) => void;
  onEdit?: (resource: PhysicsResource) => void;
}

const ResourceCard: React.FC<ResourceCardProps> = ({ resource, isAdmin, onDelete, onEdit }) => {
  const navigate = useNavigate();

  const getBadgeStyles = (type: ResourceType) => {
    switch (type) {
      case ResourceType.SIMULATION: return 'bg-indigo-600 text-white';
      case ResourceType.WORKSHEET: return 'bg-emerald-600 text-white';
      case ResourceType.CHEATSHEET: return 'bg-amber-600 text-white';
      default: return 'bg-slate-600 text-white';
    }
  };

  const getThumbnailUrl = () => {
    if (resource.thumbnailUrl && (resource.thumbnailUrl.startsWith('http') || resource.thumbnailUrl.startsWith('data:image'))) {
      return resource.thumbnailUrl;
    }
    const categoryMaps: Record<string, string> = {
      'Mechanics': 'https://images.unsplash.com/photo-1581093458791-9f3c3900df4b',
      'Astronomy': 'https://images.unsplash.com/photo-1464802686167-b939a6910659',
      'Optics': 'https://images.unsplash.com/photo-1582719471384-894fbb16e074',
      'Electricity': 'https://images.unsplash.com/photo-1517420704952-d9f39e95b43e',
      'Modern Physics': 'https://images.unsplash.com/photo-1532094349884-543bc11b234d',
      'Thermodynamics': 'https://images.unsplash.com/photo-1532187875605-7fe359843f68'
    };
    const base = categoryMaps[resource.category] || 'https://images.unsplash.com/photo-1636466497217-26a8cbeaf0aa';
    return `${base}?auto=format&fit=crop&q=80&w=800&sig=${resource.id}`;
  };

  const handleShare = async (e: React.MouseEvent) => {
    e.preventDefault();
    const shareData = {
      title: resource.title,
      text: `Check out this physics resource on Phrontier: ${resource.description}`,
      url: resource.contentUrl,
    };

    try {
      if (navigator.share) {
        await navigator.share(shareData);
      } else {
        await navigator.clipboard.writeText(resource.contentUrl);
        alert('Link copied to clipboard!');
      }
    } catch (err) {
      console.error('Share failed:', err);
    }
  };

  const handleDownload = (e: React.MouseEvent) => {
    e.preventDefault();
    const link = document.createElement('a');
    link.href = resource.contentUrl;
    link.download = `${resource.title}.${resource.type === ResourceType.CHEATSHEET ? 'pdf' : 'docx'}`;
    link.target = '_blank';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="group relative bg-[#1E293B] rounded-[2.5rem] border border-white/5 overflow-hidden shadow-2xl hover:shadow-indigo-500/20 hover:-translate-y-2 transition-all duration-500 animate-in fade-in zoom-in-95">
      <div className="h-52 sm:h-60 relative overflow-hidden">
        <img 
          src={getThumbnailUrl()} 
          alt={resource.title} 
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 brightness-75 group-hover:brightness-100" 
        />
        <div className="absolute inset-0 bg-gradient-to-t from-[#1E293B] via-transparent to-transparent opacity-80"></div>

        <div className="absolute top-5 left-5 z-10">
          <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] shadow-lg ${getBadgeStyles(resource.type)}`}>
            {resource.type}
          </span>
        </div>

        {isAdmin && (
          <div className="absolute top-5 right-5 z-20 flex gap-2">
            <button 
              onClick={(e) => { 
                e.preventDefault(); 
                if(onEdit) {
                  onEdit(resource);
                  navigate('/upload');
                }
              }}
              className="bg-white/10 backdrop-blur-md p-2.5 rounded-2xl text-white hover:bg-indigo-600 transition-all border border-white/10"
              title="Edit Resource"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"></path></svg>
            </button>
            <button 
              onClick={(e) => { e.preventDefault(); onDelete(resource.id); }}
              className="bg-white/10 backdrop-blur-md p-2.5 rounded-2xl text-white hover:bg-red-500 hover:scale-110 transition-all border border-white/10"
              title="Delete Resource"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
            </button>
          </div>
        )}
      </div>

      <div className="p-8">
        <div className="flex items-center justify-between mb-4">
          <span className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.15em] bg-indigo-500/10 px-3 py-1.5 rounded-xl border border-indigo-500/20">{resource.category}</span>
          <div className="flex gap-2">
            <button 
              onClick={handleShare}
              className="p-2 text-slate-400 hover:text-indigo-400 transition-colors"
              title="Share"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 100-2.684 3 3 0 000 2.684zm0 12.684a3 3 0 100-2.684 3 3 0 000 2.684z"></path></svg>
            </button>
            {resource.type !== ResourceType.SIMULATION && (
              <button 
                onClick={handleDownload}
                className="p-2 text-slate-400 hover:text-emerald-400 transition-colors"
                title="Download"
              >
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
              </button>
            )}
          </div>
        </div>
        <h3 className="font-black text-white text-2xl mb-3 leading-tight tracking-tight line-clamp-1 group-hover:text-indigo-400 transition-colors">{resource.title}</h3>
        <p className="text-slate-400 text-sm line-clamp-2 mb-8 leading-relaxed font-medium">{resource.description}</p>

        <Link 
          to={`/play/${resource.id}`}
          className="w-full bg-[#334155] group-hover:bg-indigo-600 text-white py-5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 transition-all duration-300"
        >
          {resource.type === ResourceType.SIMULATION ? 'Start Experiment' : 'Open Module'}
          <svg className="w-5 h-5 group-hover:translate-x-1 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M14 5l7 7m0 0l-7 7m7-7H3"></path></svg>
        </Link>
      </div>
    </div>
  );
};

