          <p className="text-indigo-300 font-bold uppercase text-[10px] tracking-[0.2em]">Synchronized with browser: {resources.length} active modules</p>
        </div>
      </div>

      {resources.length === 0 ? (
        <div className="flex flex-col items-center justify-center py-32 text-center bg-white/5 rounded-[3rem] border border-white/10 shadow-sm">
          <div className="w-24 h-24 bg-white/5 rounded-[2rem] flex items-center justify-center mb-8 border border-white/10">
            <svg className="w-10 h-10 text-slate-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9.172 9.172a4 4 0 015.656 0M9 10h.01M15 10h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
          </div>
          <h3 className="text-2xl font-black text-white mb-2 tracking-tight">Empty Discovery</h3>
          <p className="text-slate-400 max-w-xs mx-auto font-medium">We couldn't find any resources matching your search. Try adjusting keywords or clearing filters.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 2xl:grid-cols-4 gap-8">
          {resources.map((res) => (
            <ResourceCard 
              key={res.id} 
              resource={res} 
              isAdmin={isAdmin} 
              onDelete={onDelete} 
              onEdit={onEdit} 
            />
          ))}
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { PhysicsResource, ResourceType } from '../types';
import { CATEGORIES } from '../constants';
import { generateLearningOutcomes } from '../services/geminiService';

interface UploadFormProps {
  onAdd: (resource: PhysicsResource) => void;
  onUpdate: (resource: PhysicsResource) => void;
  editData: PhysicsResource | null;
}

const UploadForm: React.FC<UploadFormProps> = ({ onAdd, onUpdate, editData }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    category: CATEGORIES[0].name,
    subCategory: '',
    type: ResourceType.SIMULATION,
    author: '',
    description: '',
    userGuide: '',
    contentUrl: '',
    learningOutcomes: '',
    thumbnailUrl: ''
  });

  useEffect(() => {
    if (editData) {
      setFormData({
        ...editData,
        learningOutcomes: editData.learningOutcomes.join('\n')
      });
    }
  }, [editData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const payload = {
      ...formData,
      id: editData ? editData.id : Date.now().toString(),
      learningOutcomes: formData.learningOutcomes.split('\n').filter(o => o.trim() !== ''),
      createdAt: editData ? editData.createdAt : new Date().toISOString()
    };

    if (editData) {
      onUpdate(payload as PhysicsResource);
    } else {
      onAdd(payload as PhysicsResource);
    }
    navigate('/');
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, thumbnailUrl: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSuggestOutcomes = async () => {
    if (!formData.title || !formData.description) {
      alert("Please provide a title and description first.");
      return;
    }
    setLoading(true);
    const outcomes = await generateLearningOutcomes(formData.title, formData.category, formData.description);
    setFormData(prev => ({ ...prev, learningOutcomes: outcomes.join('\n') }));
    setLoading(false);
  };

  const checkUrlSafety = (url: string) => {
    if (url.includes('github.com') && url.includes('/blob/')) {
        const fixed = url.replace('github.com', 'raw.githack.com').replace('/blob/', '/');
        if (confirm("I noticed this is a standard GitHub link. It won't work directly. Convert to an embed-friendly URL?")) {
            setFormData(p => ({ ...p, contentUrl: fixed }));
        }
    }
  };

  return (
    <div className="max-w-4xl mx-auto pb-20 animate-in fade-in zoom-in-95 duration-700">
      <div className="flex items-center gap-6 mb-12">
        <button onClick={() => navigate(-1)} className="w-12 h-12 flex items-center justify-center bg-white/5 border border-white/10 rounded-2xl text-slate-400 hover:bg-white/10 transition-all hover:scale-110 shadow-sm">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7 7-7m8 14l-7-7 7-7"></path></svg>
        </button>
        <h1 className="text-4xl font-black text-white tracking-tight">
          {editData ? 'Edit Experiment' : 'New Lab Module'}
        </h1>
      </div>

      <form onSubmit={handleSubmit} className="space-y-10 bg-[#1E293B] p-10 rounded-[2.5rem] border border-white/10 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-48 h-48 bg-indigo-500/5 rounded-bl-[10rem] -z-0"></div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 relative z-10">
          <div className="space-y-3">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Resource Title</label>
            <input 
              required
              type="text"
              className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500/50 outline-none transition-all font-bold text-white placeholder:text-slate-600"
              placeholder="e.g. Newton's Lab"
              value={formData.title}
              onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Creator</label>
            <input 
              required
              type="text"
              className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500/50 outline-none transition-all font-bold text-white placeholder:text-slate-600"
              placeholder="Full Name"
              value={formData.author}
              onChange={(e) => setFormData({ ...formData, author: e.target.value })}
            />
          </div>

          <div className="space-y-3">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Main Category</label>
            <select 
              className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500/50 outline-none transition-all font-bold text-white"
              value={formData.category}
              onChange={(e) => setFormData({ ...formData, category: e.target.value })}
            >
              {CATEGORIES.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
            </select>
          </div>

          <div className="space-y-3">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Sub-topic</label>
            <input 
              required
              type="text"
              className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500/50 outline-none transition-all font-bold text-white placeholder:text-slate-600"
              placeholder="e.g. Gravity"
              value={formData.subCategory}
              onChange={(e) => setFormData({ ...formData, subCategory: e.target.value })}
            />
          </div>

          <div className="space-y-3 md:col-span-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Content URL</label>
            <input 
              required
              type="url"
              className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 focus:border-indigo-500/50 outline-none transition-all font-bold text-white placeholder:text-slate-600"
              placeholder="https://simulation-source.com/..."
              value={formData.contentUrl}
              onBlur={() => checkUrlSafety(formData.contentUrl)}
              onChange={(e) => setFormData({ ...formData, contentUrl: e.target.value })}
            />
          </div>

          <div className="space-y-3 md:col-span-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Custom Thumbnail</label>
            <div className="flex gap-4 items-center">
              <div className="relative group flex-1">
                <input 
                  type="text"
                  className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 transition-all font-bold text-white placeholder:text-slate-600"
                  placeholder="Paste URL or upload image ->"
                  value={formData.thumbnailUrl}
                  onChange={(e) => setFormData({ ...formData, thumbnailUrl: e.target.value })}
                />
              </div>
              <label className="shrink-0 bg-indigo-600 text-white px-6 py-4 rounded-[1.25rem] font-black text-[10px] uppercase tracking-widest cursor-pointer hover:bg-indigo-500 transition-colors">
                Upload File
                <input type="file" className="hidden" accept="image/*" onChange={handleImageUpload} />
              </label>
            </div>
            {formData.thumbnailUrl && (
              <div className="mt-4 h-24 w-40 rounded-2xl overflow-hidden border border-white/10">
                <img src={formData.thumbnailUrl} alt="Preview" className="w-full h-full object-cover" />
              </div>
            )}
          </div>
        </div>

        <div className="space-y-3 relative z-10">
          <label className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Brief Narrative</label>
          <textarea 
            required
            rows={2}
            className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 outline-none transition-all font-bold text-white placeholder:text-slate-600 resize-none"
            placeholder="Tell the student what they'll discover..."
            value={formData.description}
            onChange={(e) => setFormData({ ...formData, description: e.target.value })}
          />
        </div>

        <div className="space-y-4 relative z-10">
          <div className="flex items-center justify-between px-1">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Expected Outcomes</label>
            <button 
              type="button"
              onClick={handleSuggestOutcomes}
              disabled={loading}
              className="text-indigo-400 text-[10px] font-black uppercase tracking-[0.15em] hover:text-indigo-300 transition-colors flex items-center gap-2 bg-indigo-500/10 px-3 py-1.5 rounded-lg border border-indigo-500/20"
            >
              {loading ? (
                  <span className="flex items-center gap-2"><div className="w-3 h-3 border-2 border-indigo-400 border-t-transparent rounded-full animate-spin"></div> Thinking...</span>
              ) : '✨ Gemini Suggest'}
            </button>
          </div>
          <textarea 
            required
            rows={4}
            className="w-full px-6 py-4 rounded-[1.25rem] bg-[#0F172A] border border-white/5 focus:ring-4 focus:ring-indigo-500/20 outline-none transition-all font-bold text-white placeholder:text-slate-600"
            placeholder="One key outcome per line..."
            value={formData.learningOutcomes}
            onChange={(e) => setFormData({ ...formData, learningOutcomes: e.target.value })}
          />
        </div>

        <div className="pt-10 border-t border-white/5 flex flex-col sm:flex-row justify-end gap-4 relative z-10">
          <button 
            type="button"
            onClick={() => navigate(-1)}
            className="px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest text-slate-500 hover:text-slate-400 transition-all"
          >
            Cancel
          </button>
          <button 
            type="submit"
            className="px-12 py-5 bg-indigo-600 text-white rounded-[1.5rem] font-black text-xs uppercase tracking-widest shadow-[0_20px_40px_-15px_rgba(79,70,229,0.3)] hover:bg-indigo-700 hover:-translate-y-1 active:translate-y-0 transition-all"
          >
            {editData ? 'Save Changes' : 'Publish Experiment'}
          </button>
        </div>
      </form>
    </div>
  );
};

