          const data = await response.json();
          setResources(Array.isArray(data) ? data : []);
        }
      } catch (e) {
        console.error("Failed to fetch cloud resources", e);
      } finally {
        setLoading(false);
      }
    };

    if (user) fetchResources();
  }, [user]);

  const login = (role: UserRole) => {
