      token: token
    });

    return new Response(JSON.stringify({ url: blob.url }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });
  } catch (error: any) {
    console.error("Critical Upload Error:", error);
    return new Response(JSON.stringify({ 
