import { put } from '@vercel/blob';

// Edge runtime handles binary Request bodies much better than Node.js for streaming
export const runtime = 'edge';
export const dynamic = 'force-dynamic';

export default async function handler(request: Request) {
  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method Not Allowed' }), { 
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const token = process.env.BLOB_READ_WRITE_TOKEN;
  if (!token) {
    return new Response(JSON.stringify({ 
      error: 'CRITICAL: BLOB_READ_WRITE_TOKEN is not configured in Vercel Environment Variables.' 
    }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  try {
    // Standardize metadata from headers
    const rawFilename = request.headers.get('x-filename') || 'unnamed-file';
    const filename = decodeURIComponent(rawFilename);
    const contentType = request.headers.get('x-content-type') || 'application/octet-stream';

    // Read the binary stream directly from the request
    const body = request.body;

    if (!body) {
      return new Response(JSON.stringify({ error: 'No file content found in request body.' }), { 
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Direct upload to Vercel Blob via Edge Stream
    const blob = await put(filename, body, {
      access: 'public',
      addRandomSuffix: true,
      contentType: contentType,
      token: token
    });

    return new Response(JSON.stringify({ 
      success: true,
      url: blob.url 
    }), {
      status: 200,
      headers: { 'Content-Type': 'application/json' },
    });
  } catch (error: any) {
    console.error("Vercel Edge Upload Error:", error);
    return new Response(JSON.stringify({ 
      error: error.message || 'Internal Cloud Sync Failure' 
    }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { PhysicsResource, ResourceType } from '../types';
import { CATEGORIES } from '../constants';

interface UploadFormProps {
  onAdd: (resource: PhysicsResource) => void;
  onUpdate: (resource: PhysicsResource) => void;
  editData: PhysicsResource | null;
}

const UploadForm: React.FC<UploadFormProps> = ({ onAdd, onUpdate, editData }) => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    title: '',
    category: CATEGORIES[0].name,
    subCategory: '',
    type: ResourceType.SIMULATION,
    author: '',
    description: '',
    userGuide: '',
    contentUrl: '',
    learningOutcomes: '',
    thumbnailUrl: ''
  });

  useEffect(() => {
    if (editData) {
      setFormData({
        ...editData,
        learningOutcomes: Array.isArray(editData.learningOutcomes) ? editData.learningOutcomes.join('\n') : ''
      });
    }
  }, [editData]);

  // The most stable binary upload method for modern browsers to Vercel Edge
  const uploadToCloud = async (file: File) => {
    setUploading(`Preparing ${file.name}...`);

    // Safety check for file size (Edge handles more but let's be reasonable)
    if (file.size > 25 * 1024 * 1024) {
      alert("File is too large. Max limit is 25MB for Edge uploads.");
      setUploading(null);
      throw new Error("File too large");
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 120000); // 2 minute timeout

    try {
      setUploading(`Transmitting ${file.name} to Cloud Vault...`);

      const response = await fetch('/api/upload', {
        method: 'POST',
        body: file, // Send binary directly
        headers: {
          'x-filename': encodeURIComponent(file.name),
          'x-content-type': file.type
        },
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      const responseText = await response.text();
      let result;
      try {
        result = JSON.parse(responseText);
      } catch (e) {
        throw new Error(`Server returned invalid response: ${responseText.substring(0, 100)}`);
      }

      if (!response.ok) {
        throw new Error(result.error || 'Cloud synchronization failed.');
      }

      return result.url;
    } catch (e: any) {
      console.error("Cloud Upload Debug Log:", e);
      let errorMsg = "Cloud Sync Error";
      if (e.name === 'AbortError') {
