import { GoogleGenAI } from "@google/genai";

export const runtime = 'nodejs';

export default async function handler(request: Request) {
  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: 'System configuration error: API Key missing.' }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  try {
    const { task, title, description } = await request.json();
    const ai = new GoogleGenAI({ apiKey: apiKey });

    if (task === 'thumbnail') {
      // Simplified prompt to avoid safety filters and speed up generation
      const prompt = `A professional 3D scientific visualization of: ${title}. ${description}. Laboratory aesthetic, bright cinematic lighting, high-tech, 1:1 ratio, no text.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { 
          imageConfig: { aspectRatio: "1:1" }
        },
      });

      if (response.candidates && response.candidates[0]?.content?.parts) {
        const imagePart = response.candidates[0].content.parts.find(p => p.inlineData);
        if (imagePart?.inlineData?.data) {
          return new Response(JSON.stringify({ data: imagePart.inlineData.data }), {
            headers: { 'Content-Type': 'application/json' }
          });
        }
      }
      throw new Error("Gemini produced no valid image data.");
    }

    return new Response('Invalid Task', { status: 400 });
  } catch (error: any) {
    console.error("AI Node Error:", error);
    return new Response(JSON.stringify({ error: error.message || "AI Generation Timeout" }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }
}

import { kv } from '@vercel/kv';
import { GoogleGenAI, Type } from "@google/genai";

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

const KV_KEY = 'phrontier_global_v2';

export default async function handler(request: Request) {
  const { method, url } = request;
  const urlObj = new URL(url);
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    if (method === 'GET') {
      const resources = await kv.get(KV_KEY);
      return new Response(JSON.stringify(resources || []), {
        status: 200,
        headers: { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' },
      });
    }

    if (method === 'POST' || method === 'PATCH') {
      const payload = await request.json();

      // Auto-generate learning outcomes on the server if they don't exist
      if (!payload.learningOutcomes || payload.learningOutcomes.length === 0) {
        try {
          const aiRes = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Generate 3 learning outcomes for physics simulation: ${payload.title}. Description: ${payload.description}`,
            config: {
              responseMimeType: "application/json",
              responseSchema: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          });
          payload.learningOutcomes = JSON.parse(aiRes.text);
        } catch (e) {
          payload.learningOutcomes = ["Master " + payload.title, "Analyze experimental data", "Understand physical principles"];
        }
      }

      let current: any[] = (await kv.get(KV_KEY)) || [];
      if (method === 'POST') {
        current = [payload, ...current];
      } else {
        current = current.map((item: any) => item.id === payload.id ? payload : item);
      }

      await kv.set(KV_KEY, current);
      return new Response(JSON.stringify({ success: true }), { status: 200 });
    }

    if (method === 'DELETE') {
      const id = urlObj.searchParams.get('id');
      let current: any[] = (await kv.get(KV_KEY)) || [];
      await kv.set(KV_KEY, current.filter((item: any) => item.id !== id));
      return new Response(JSON.stringify({ success: true }), { status: 200 });
    }

    return new Response('Not Allowed', { status: 405 });
  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}

