import { GoogleGenAI } from "@google/genai";

export const runtime = 'nodejs';

export default async function handler(request: Request) {
  if (request.method !== 'POST') {
    return new Response('Method Not Allowed', { status: 405 });
  }

  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    return new Response(JSON.stringify({ error: 'Config error' }), { status: 500 });
  }

  try {
    const { task, title, category } = await request.json();
    const ai = new GoogleGenAI({ apiKey: apiKey });

    if (task === 'thumbnail') {
      // Stripped down prompt for maximum speed and safety
      const prompt = `A clean, professional 3D scientific 3D illustration: ${title} in the context of ${category}. High-tech laboratory style, cinematic lighting, 1:1 ratio, no text.`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { 
          imageConfig: { aspectRatio: "1:1" }
        },
      });

      const imagePart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
      if (imagePart?.inlineData?.data) {
        return new Response(JSON.stringify({ data: imagePart.inlineData.data }), {
          headers: { 'Content-Type': 'application/json' }
        });
      }
      throw new Error("No image generated");
    }

    return new Response('Invalid Task', { status: 400 });
  } catch (error: any) {
    return new Response(JSON.stringify({ error: "AI Busy" }), { status: 500 });
  }
}

import { kv } from '@vercel/kv';
import { GoogleGenAI, Type } from "@google/genai";

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

const KV_KEY = 'phrontier_global_v2';

export default async function handler(request: Request) {
  const { method, url } = request;
  const urlObj = new URL(url);
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    if (method === 'GET') {
      const resources = await kv.get(KV_KEY);
      return new Response(JSON.stringify(resources || []), {
        status: 200,
        headers: { 'Content-Type': 'application/json' },
      });
    }

    if (method === 'POST' || method === 'PATCH') {
      const payload = await request.json();

      // Fast Learning Outcome Generation (Server-side)
      if (!payload.learningOutcomes || payload.learningOutcomes.length === 0) {
        try {
          const aiRes = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Briefly list 3 physics targets for: ${payload.title}.`,
            config: {
              responseMimeType: "application/json",
              responseSchema: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          });
          payload.learningOutcomes = JSON.parse(aiRes.text);
        } catch (e) {
          payload.learningOutcomes = ["Understand " + payload.title, "Analyze physics data", "Apply principles"];
        }
      }

      let current: any[] = (await kv.get(KV_KEY)) || [];
      if (method === 'POST') {
        current = [payload, ...current];
      } else {
        current = current.map((item: any) => item.id === payload.id ? payload : item);
      }

      await kv.set(KV_KEY, current);
      return new Response(JSON.stringify({ success: true }), { status: 200 });
    }

    if (method === 'DELETE') {
      const id = urlObj.searchParams.get('id');
      let current: any[] = (await kv.get(KV_KEY)) || [];
      await kv.set(KV_KEY, current.filter((item: any) => item.id !== id));
      return new Response(JSON.stringify({ success: true }), { status: 200 });
    }

    return new Response('Method Not Allowed', { status: 405 });
  } catch (error: any) {
    return new Response(JSON.stringify({ error: error.message }), { status: 500 });
  }
}

