import { put } from '@vercel/blob';

// Forced to Node.js runtime for maximum compatibility with SDKs
export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

export default async function handler(request: Request) {
  if (request.method !== 'POST') {
    return new Response(JSON.stringify({ error: 'Method Not Allowed' }), { 
      status: 405,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  // Token is automatically injected by Vercel
  const token = process.env.BLOB_READ_WRITE_TOKEN;
  if (!token) {
    return new Response(JSON.stringify({ 
      error: 'CRITICAL: Blob Storage Token not found. Please check your Vercel Environment Variables.' 
    }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  try {
    const rawFilename = request.headers.get('x-filename') || `sync-file-${Date.now()}`;
    const filename = decodeURIComponent(rawFilename);
    const contentType = request.headers.get('x-content-type') || 'application/octet-stream';

    // Using standard web-api ArrayBuffer for cross-runtime safety
    const buffer = await request.arrayBuffer();

    if (!buffer || buffer.byteLength === 0) {
      return new Response(JSON.stringify({ error: 'Sync failed: Payload was empty.' }), { 
        status: 400,
        headers: { 'Content-Type': 'application/json' }
      });
    }

    // Upload using the Vercel Blob SDK
    const blob = await put(filename, Buffer.from(buffer), {
      access: 'public',
      addRandomSuffix: true,
      contentType: contentType,
      token: token
    });

    return new Response(JSON.stringify({ 
      success: true,
      url: blob.url 
    }), {
      status: 200,
      headers: { 
        'Content-Type': 'application/json',
        'Cache-Control': 'no-store'
      },
    });
  } catch (error: any) {
    console.error("Vercel Node.js Upload Error:", error);
    return new Response(JSON.stringify({ 
      error: 'The cloud storage system encountered an error: ' + (error.message || 'Unknown Error')
    }), {
      status: 500,
      headers: { 'Content-Type': 'application/json' },
    });
  }
}

import { kv } from '@vercel/kv';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

const KV_KEY = 'phrontier_global_v2';
const MAX_ITEMS = 20;

export default async function handler(request: Request) {
  const { method } = request;

  if (!process.env.KV_REST_API_URL || !process.env.KV_REST_API_TOKEN) {
    return new Response(JSON.stringify({ error: "Cloud database configuration missing." }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  try {
    if (method === 'GET') {
      const resources = await kv.get(KV_KEY);
      return new Response(JSON.stringify(resources || []), {
        status: 200,
        headers: { 'Content-Type': 'application/json; charset=utf-8' },
      });
    }

    if (method === 'POST' || method === 'PATCH') {
      const payload = await request.json();

      // Sanitization to prevent DB bloat
      if (payload.thumbnailUrl && payload.thumbnailUrl.length > 5000) {
        payload.thumbnailUrl = ''; // Strip large failed strings
      }

      let current: any[] = (await kv.get(KV_KEY)) || [];

      if (method === 'POST') {
        current = [payload, ...current].slice(0, MAX_ITEMS);
      } else {
        current = current.map((item: any) => item.id === payload.id ? payload : item);
      }

      await kv.set(KV_KEY, current);
      return new Response(JSON.stringify({ success: true }), { 
        status: 200,
        headers: { 'Content-Type': 'application/json; charset=utf-8' }
      });
    }

    if (method === 'DELETE') {
      const urlObj = new URL(request.url);
      const id = urlObj.searchParams.get('id');
      let current: any[] = (await kv.get(KV_KEY)) || [];
      await kv.set(KV_KEY, current.filter((item: any) => item.id !== id));
      return new Response(JSON.stringify({ success: true }), { 
        status: 200,
        headers: { 'Content-Type': 'application/json; charset=utf-8' }
      });
    }

    return new Response(JSON.stringify({ error: 'Method Not Allowed' }), { status: 405 });
  } catch (error: any) {
    console.error("KV Node.js Error:", error);
    return new Response(JSON.stringify({ error: "Cloud sync failed: " + (error.message || "Internal Server Error") }), { 
      status: 500,
      headers: { 'Content-Type': 'application/json; charset=utf-8' }
    });
  }
}

